import{_ as e,o as r,c as o,ag as t}from"./chunks/framework.DjqkqlVQ.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"mods/xuanji-character/faq.md","filePath":"mods/xuanji-character/faq.md","lastUpdated":1779001232000}'),d={name:"mods/xuanji-character/faq.md"};function h(i,a,n,l,s,c){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="玄羁是什么类型的-mod" tabindex="-1">玄羁是什么类型的 Mod？ <a class="header-anchor" href="#玄羁是什么类型的-mod" aria-label="Permalink to &quot;玄羁是什么类型的 Mod？&quot;">​</a></h2><p>玄羁是《杀戮尖塔2》的自定义角色 Mod。他围绕纳编、机匣、凝核和羁绊进度构筑，会加入新角色、专属卡牌、专属遗物和新的战斗节奏。</p><h2 id="当前版本适合正式游玩吗" tabindex="-1">当前版本适合正式游玩吗？ <a class="header-anchor" href="#当前版本适合正式游玩吗" aria-label="Permalink to &quot;当前版本适合正式游玩吗？&quot;">​</a></h2><p>当前是 Beta 版本，可以体验核心玩法，但数值、卡池、UI 和兼容性仍可能继续调整。建议把它当作预览版本使用。</p><h2 id="需要安装前置吗" tabindex="-1">需要安装前置吗？ <a class="header-anchor" href="#需要安装前置吗" aria-label="Permalink to &quot;需要安装前置吗？&quot;">​</a></h2><p>需要安装 <code>BaseLib</code>。</p><h2 id="纳编-是什么意思" tabindex="-1">“纳编”是什么意思？ <a class="header-anchor" href="#纳编-是什么意思" aria-label="Permalink to &quot;“纳编”是什么意思？&quot;">​</a></h2><p>带纳编的牌打出后会进入机匣。机匣集齐 3 张牌时会凝成机核；已经完成凝核的牌，本场战斗不会再次贡献羁绊。</p><h2 id="机核有什么用" tabindex="-1">机核有什么用？ <a class="header-anchor" href="#机核有什么用" aria-label="Permalink to &quot;机核有什么用？&quot;">​</a></h2><p>机核提供羁绊进度，也会根据主标签提供主机核效果。比如固守机核偏防守，突袭机核偏首攻伤害，超载机核偏能量。</p><h2 id="为什么有时同一张牌不会再次贡献羁绊" tabindex="-1">为什么有时同一张牌不会再次贡献羁绊？ <a class="header-anchor" href="#为什么有时同一张牌不会再次贡献羁绊" aria-label="Permalink to &quot;为什么有时同一张牌不会再次贡献羁绊？&quot;">​</a></h2><p>这是纳编系统的核心限制。牌完成凝核后会进入“已纳编”状态，避免同一张牌在一场战斗里反复刷羁绊。</p><h2 id="羁绊详情在哪里看" tabindex="-1">羁绊详情在哪里看？ <a class="header-anchor" href="#羁绊详情在哪里看" aria-label="Permalink to &quot;羁绊详情在哪里看？&quot;">​</a></h2><p>见 <a href="/jasonsong-games/mods/xuanji-character/synergies">羁绊详情</a>。该页面列出每种羁绊的主机核效果、阈值和每档效果。</p><h2 id="支持哪些语言" tabindex="-1">支持哪些语言？ <a class="header-anchor" href="#支持哪些语言" aria-label="Permalink to &quot;支持哪些语言？&quot;">​</a></h2><p>当前主要维护英文和简体中文。后续若补充更多语言，会同步检查用户可见文本，避免缺 key 或旧文案残留。</p><h2 id="可以和其他-mod-一起用吗" tabindex="-1">可以和其他 Mod 一起用吗？ <a class="header-anchor" href="#可以和其他-mod-一起用吗" aria-label="Permalink to &quot;可以和其他 Mod 一起用吗？&quot;">​</a></h2><p>可以尝试，但这是会影响玩法的自定义角色 Mod。若其他 Mod 修改角色、卡池、遗物、战斗 UI、BaseLib 行为或游戏内部 API，可能存在兼容性风险。</p><h2 id="可以转载或打包进整合包吗" tabindex="-1">可以转载或打包进整合包吗？ <a class="header-anchor" href="#可以转载或打包进整合包吗" aria-label="Permalink to &quot;可以转载或打包进整合包吗？&quot;">​</a></h2><p>未经许可，请勿转载、重新上传、打包进付费整合包，或分发修改后的版本。</p>',21)])])}const m=e(d,[["render",h]]);export{u as __pageData,m as default};
